import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { accordionVariants, type AccordionVariants } from './accordion.variants';
import { ACCORDION_CONTEXT, type AccordionContext } from './accordion.tokens';

@Component({
  selector: 'n-accordion',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { '[class]': 'classes()' },
  providers: [
    {
      provide: ACCORDION_CONTEXT,
      useFactory: (cmp: AccordionComponent) => cmp.context,
      deps: [forwardRef(() => AccordionComponent)],
    },
  ],
})
export class AccordionComponent {
  readonly nVariant     = input<AccordionVariants['nVariant']>('default');
  readonly nSize        = input<AccordionVariants['nSize']>('default');
  readonly nType        = input<'single' | 'multiple'>('single');
  readonly nCollapsible = input<boolean>(true);
  readonly nClass       = input<string>('');

  readonly nValue  = model<string>('');
  readonly nValues = model<string[]>([]);

  readonly nOpenChange = output<string | string[]>();

  private readonly _openValues = computed<Set<string>>(() => {
    if (this.nType() === 'single') {
      const v = this.nValue();
      return v ? new Set([v]) : new Set();
    }
    return new Set(this.nValues());
  });

  protected readonly classes = computed(() =>
    mergeClasses(accordionVariants({ nVariant: this.nVariant(), nSize: this.nSize() }), this.nClass()),
  );

  readonly context: AccordionContext = {
    type: this.nType,
    collapsible: this.nCollapsible,
    openValues: this._openValues,
    toggle: (value: string) => {
      if (this.nType() === 'single') {
        const isOpen = this.nValue() === value;
        if (isOpen && !this.nCollapsible()) return;
        const next = isOpen ? '' : value;
        this.nValue.set(next);
        this.nOpenChange.emit(next);
      } else {
        const current = this.nValues();
        const isOpen = current.includes(value);
        const next = isOpen
          ? current.filter(v => v !== value)
          : [...current, value];
        this.nValues.set(next);
        this.nOpenChange.emit(next);
      }
    },
  };
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { ACCORDION_CONTEXT, ACCORDION_ITEM_CONTEXT, type AccordionItemContext } from './accordion.tokens';

let _accordionItemCounter = 0;

@Component({
  selector: 'n-accordion-item',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.data-state]': 'isOpen() ? "open" : "closed"',
    '[attr.data-disabled]': 'nDisabled() ? "" : null',
    'data-slot': 'item',
  },
  providers: [
    {
      provide: ACCORDION_ITEM_CONTEXT,
      useFactory: (cmp: AccordionItemComponent) => cmp.itemContext,
      deps: [forwardRef(() => AccordionItemComponent)],
    },
  ],
})
export class AccordionItemComponent {
  private readonly _ctx = inject(ACCORDION_CONTEXT);
  private readonly _id  = `n-accordion-item-${++_accordionItemCounter}`;

  readonly nValue    = input.required<string>();
  readonly nDisabled = input<boolean>(false);
  readonly nClass    = input<string>('');

  protected readonly isOpen = computed(() => this._ctx.openValues().has(this.nValue()));

  protected readonly classes = computed(() => mergeClasses('block', this.nClass()));

  readonly itemContext: AccordionItemContext = {
    value:     this.nValue,
    disabled:  this.nDisabled,
    isOpen:    this.isOpen,
    triggerId: `${this._id}-trigger`,
    contentId: `${this._id}-content`,
  };
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { ACCORDION_CONTEXT, ACCORDION_ITEM_CONTEXT } from './accordion.tokens';

@Component({
  selector: 'n-accordion-trigger, button[n-accordion-trigger]',
  standalone: true,
  template: `
    <span class="flex-1 text-left">
      <ng-content />
    </span>

    @if (nIcon() === 'chevron') {
      <svg
        class="h-4 w-4 shrink-0 transition-transform duration-200"
        [class.rotate-180]="isOpen()"
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
      >
        <path d="m6 9 6 6 6-6" />
      </svg>
    } @else {
      <svg
        class="h-4 w-4 shrink-0 transition-transform duration-200"
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        stroke-width="2"
        stroke-linecap="round"
        stroke-linejoin="round"
        aria-hidden="true"
      >
        <path d="M5 12h14" />
        @if (!isOpen()) {
          <path d="M12 5v14" />
        }
      </svg>
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    '[class]': 'classes()',
    '[attr.id]': 'itemCtx.triggerId',
    '[attr.aria-expanded]': 'isOpen()',
    '[attr.aria-controls]': 'itemCtx.contentId',
    '[attr.disabled]': 'isDisabled() ? true : null',
    '[attr.aria-disabled]': 'isDisabled() ? true : null',
    'data-slot': 'trigger',
    '(click)': 'handleClick()',
    '(keydown.enter)': 'handleKeydown($event)',
    '(keydown.space)': 'handleKeydown($event)',
  },
})
export class AccordionTriggerComponent {
  private readonly _ctx = inject(ACCORDION_CONTEXT);
  protected readonly itemCtx = inject(ACCORDION_ITEM_CONTEXT);

  readonly nIcon  = input<'chevron' | 'plus-minus'>('chevron');
  readonly nClass = input<string>('');

  protected readonly isOpen    = computed(() => this.itemCtx.isOpen());
  protected readonly isDisabled = computed(() => this.itemCtx.disabled());

  protected readonly classes = computed(() =>
    mergeClasses(
      'flex w-full items-center justify-between px-4 py-4 text-sm font-medium transition-all' +
      ' hover:underline focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring' +
      ' focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50',
      this.nClass(),
    ),
  );

  protected handleClick(): void {
    if (this.isDisabled()) return;
    this._ctx.toggle(this.itemCtx.value());
  }

  protected handleKeydown(event: Event): void {
    if (this.isDisabled()) return;
    event.preventDefault();
    this._ctx.toggle(this.itemCtx.value());
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { ACCORDION_ITEM_CONTEXT } from './accordion.tokens';

@Component({
  selector: 'n-accordion-content',
  standalone: true,
  template: `
    <div
      class="grid transition-[grid-template-rows] duration-200 ease-out"
      [style.grid-template-rows]="isOpen() ? '1fr' : '0fr'"
    >
      <div class="overflow-hidden">
        @if (shouldRender()) {
          <div [class]="contentClasses()" data-slot="content">
            <ng-content />
          </div>
        }
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'role': 'region',
    '[attr.id]': 'itemCtx.contentId',
    '[attr.aria-labelledby]': 'itemCtx.triggerId',
    'class': 'block',
  },
})
export class AccordionContentComponent {
  protected readonly itemCtx = inject(ACCORDION_ITEM_CONTEXT);

  readonly nClass = input<string>('');

  protected readonly isOpen = computed(() => this.itemCtx.isOpen());

  private readonly _hasBeenOpened = signal(false);

  protected readonly shouldRender = computed(() => this._hasBeenOpened() || this.isOpen());

  protected readonly contentClasses = computed(() =>
    mergeClasses('px-4 pb-4 pt-0 text-sm text-foreground', this.nClass()),
  );

  constructor() {
    effect(() => {
      if (this.isOpen() && !this._hasBeenOpened()) {
        this._hasBeenOpened.set(true);
      }
    });
  }
}

import { InjectionToken, Signal } from '@angular/core';

export interface AccordionContext {
  readonly type: Signal<'single' | 'multiple'>;
  readonly collapsible: Signal<boolean>;
  readonly openValues: Signal<Set<string>>;
  toggle(value: string): void;
}

export interface AccordionItemContext {
  readonly value: Signal<string>;
  readonly disabled: Signal<boolean>;
  readonly isOpen: Signal<boolean>;
  readonly triggerId: string;
  readonly contentId: string;
}

export const ACCORDION_CONTEXT = new InjectionToken<AccordionContext>('AccordionContext');
export const ACCORDION_ITEM_CONTEXT = new InjectionToken<AccordionItemContext>('AccordionItemContext');

import { cva, type VariantProps } from 'class-variance-authority';

export const accordionVariants = cva('w-full', {
  variants: {
    nVariant: {
      default: 'border border-border rounded-md divide-y divide-border',
      ghost:   'divide-y divide-border',
      flush:   'divide-y divide-border [&_[data-slot=trigger]]:px-0 [&_[data-slot=content]]:px-0',
    },
    nSize: {
      sm:      '[&_[data-slot=trigger]]:py-2 [&_[data-slot=trigger]]:text-sm [&_[data-slot=content]]:text-sm',
      default: '',
      lg:      '[&_[data-slot=trigger]]:py-5 [&_[data-slot=trigger]]:text-lg',
    },
  },
  defaultVariants: { nVariant: 'default', nSize: 'default' },
});

export type AccordionVariants = VariantProps<typeof accordionVariants>;

export { AccordionComponent } from './accordion.component';
export { AccordionItemComponent } from './accordion-item.component';
export { AccordionTriggerComponent } from './accordion-trigger.component';
export { AccordionContentComponent } from './accordion-content.component';
export { ACCORDION_CONTEXT, ACCORDION_ITEM_CONTEXT } from './accordion.tokens';
export type { AccordionContext, AccordionItemContext } from './accordion.tokens';
export { accordionVariants } from './accordion.variants';
export type { AccordionVariants } from './accordion.variants';

