import { Component } from '@angular/core';
import { AccordionComponent } from '../accordion.component';
import { AccordionItemComponent } from '../accordion-item.component';
import { AccordionTriggerComponent } from '../accordion-trigger.component';
import { AccordionContentComponent } from '../accordion-content.component';

@Component({
  selector: 'demo-accordion-custom-icon',
  standalone: true,
  imports: [AccordionComponent, AccordionItemComponent, AccordionTriggerComponent, AccordionContentComponent],
  template: `
    <n-accordion nVariant="ghost">
      <n-accordion-item nValue="item-1">
        <button n-accordion-trigger nIcon="plus-minus">Pergunta frequente 1</button>
        <n-accordion-content>Resposta para a primeira pergunta frequente do produto.</n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-2">
        <button n-accordion-trigger nIcon="plus-minus">Pergunta frequente 2</button>
        <n-accordion-content>Resposta para a segunda pergunta frequente do produto.</n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-3">
        <button n-accordion-trigger nIcon="plus-minus">Pergunta frequente 3</button>
        <n-accordion-content>Resposta para a terceira pergunta frequente do produto.</n-accordion-content>
      </n-accordion-item>
    </n-accordion>
  `,
})
export class AccordionCustomIconDemo {}

import { Component } from '@angular/core';
import { AccordionComponent } from '../accordion.component';
import { AccordionItemComponent } from '../accordion-item.component';
import { AccordionTriggerComponent } from '../accordion-trigger.component';
import { AccordionContentComponent } from '../accordion-content.component';

@Component({
  selector: 'demo-accordion-disabled',
  standalone: true,
  imports: [AccordionComponent, AccordionItemComponent, AccordionTriggerComponent, AccordionContentComponent],
  template: `
    <n-accordion>
      <n-accordion-item nValue="item-1">
        <button n-accordion-trigger>Item ativo</button>
        <n-accordion-content>Este item funciona normalmente.</n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-2" [nDisabled]="true">
        <button n-accordion-trigger>Item desabilitado</button>
        <n-accordion-content>Este conteúdo não pode ser acessado.</n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-3">
        <button n-accordion-trigger>Outro item ativo</button>
        <n-accordion-content>Este item também funciona normalmente.</n-accordion-content>
      </n-accordion-item>
    </n-accordion>
  `,
})
export class AccordionDisabledDemo {}

import { Component, signal } from '@angular/core';
import { AccordionComponent } from '../accordion.component';
import { AccordionItemComponent } from '../accordion-item.component';
import { AccordionTriggerComponent } from '../accordion-trigger.component';
import { AccordionContentComponent } from '../accordion-content.component';

@Component({
  selector: 'demo-accordion-multiple',
  standalone: true,
  imports: [AccordionComponent, AccordionItemComponent, AccordionTriggerComponent, AccordionContentComponent],
  template: `
    <n-accordion nType="multiple" [(nValues)]="openItems">
      <n-accordion-item nValue="item-1">
        <button n-accordion-trigger>Seção 1</button>
        <n-accordion-content>
          Conteúdo da primeira seção. No modo múltiplo, vários itens podem ficar abertos simultaneamente.
        </n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-2">
        <button n-accordion-trigger>Seção 2</button>
        <n-accordion-content>
          Conteúdo da segunda seção. Abrir este item não fecha o anterior.
        </n-accordion-content>
      </n-accordion-item>

      <n-accordion-item nValue="item-3">
        <button n-accordion-trigger>Seção 3</button>
        <n-accordion-content>
          Conteúdo da terceira seção.
        </n-accordion-content>
      </n-accordion-item>
    </n-accordion>

    <p class="mt-4 text-sm text-muted-foreground">Abertos: {{ openItems().join(', ') || 'nenhum' }}</p>
  `,
})
export class AccordionMultipleDemo {
  openItems = signal<string[]>([]);
}
